// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// Tambahkan userRole di sini
const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const [isOpen, setIsOpen] = useState(false);
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
        setIsOpen(false);
    };

    const getMenuStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        color: hoveredMenu === menuId ? '#ea580c' : '#fff',
        fontWeight: '700',
        cursor: 'pointer',
        fontSize: '14px',
        transition: 'color 0.3s ease'
    });

    return (
        <nav style={{ 
            display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
            padding: '20px 5%', background: '#0c0a09', borderBottom: '1px solid #262626', position: 'relative'
        }}>
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h2 style={{ color: '#fef3c7', margin: 0, fontSize: '20px' }}>PasukanYerusSolo</h2>
            </div>

            <div className="nav-menu" style={{ display: 'flex', gap: '25px' }}>
                <button style={getMenuStyle('home')} onClick={() => navigateTo('/', 'home')} onMouseEnter={() => setHoveredMenu('home')} onMouseLeave={() => setHoveredMenu(null)}>Beranda</button>
                <button style={getMenuStyle('lowongan')} onClick={() => navigateTo('/eksplorasi', 'lowongan')} onMouseEnter={() => setHoveredMenu('lowongan')} onMouseLeave={() => setHoveredMenu(null)}>Lowongan</button>

                {/* LOGIKA PERUBAHAN MENU */}
                {isAuthenticated && userRole === 'HRD' && (
                    <>
                        <button style={getMenuStyle('dashboard')} onClick={() => navigateTo('/hrd/dashboard', 'dashboard')} onMouseEnter={() => setHoveredMenu('dashboard')} onMouseLeave={() => setHoveredMenu(null)}>Dashboard</button>
                        <button style={getMenuStyle('branding')} onClick={() => navigateTo('/hrd/branding', 'branding')} onMouseEnter={() => setHoveredMenu('branding')} onMouseLeave={() => setHoveredMenu(null)}>Branding</button>
                    </>
                )}
                {isAuthenticated && userRole === 'Pelamar' && (
                    <button style={getMenuStyle('profil')} onClick={() => navigateTo('/profil', 'profil')} onMouseEnter={() => setHoveredMenu('profil')} onMouseLeave={() => setHoveredMenu(null)}>Profil Saya</button>
                )}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                {isAuthenticated ? (
                    <button onClick={handleLogout} style={{ padding: '6px 16px', borderRadius: '20px', border: '1px solid #ef4444', background: hoveredMenu === 'logout' ? '#ef4444' : 'transparent', color: hoveredMenu === 'logout' ? '#fff' : '#ef4444', fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' }} onMouseEnter={() => setHoveredMenu('logout')} onMouseLeave={() => setHoveredMenu(null)}>Keluar</button>
                ) : (
                    <button onClick={() => navigate('/login')} style={{ padding: '6px 16px', borderRadius: '20px', border: '1px solid #ea580c', background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', color: hoveredMenu === 'login' ? '#fff' : '#ea580c', fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' }} onMouseEnter={() => setHoveredMenu('login')} onMouseLeave={() => setHoveredMenu(null)}>Login</button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
